#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <climits>
#include <cstring>
#include <ctime>
using namespace std;

// Node
struct ListNode
{
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

// Solution
class Solution
{
public:
    ListNode* deleteSecondNode(ListNode* head)
    {
        if (head == NULL) return head;
        if (head->next == NULL) return head;
        ListNode* prev = head;
        ListNode* node = head->next;
        while (node->next != NULL)
        {
            prev = node;
            node = node->next;
        }
        prev->next = node->next;
        return head;
    }
};

// Read input from stdin
void readInput(vector<int>& nums, ListNode** head)
{
    int c;
    while ((c = getchar()) != EOF && c != ' ' && c != '
')
    {
        nums.push_back(c - '0');
    }
    *head = new ListNode(nums[0]);
    ListNode* node = *head;
    for (int i = 1; i < nums.size(); i++)
    {
        node->next = new ListNode(nums[i]);
        node = node->next;
    }
}

// Print output
void printList(ListNode* node)
{
    while (node != NULL)
    {
        cout << node->val << '-> '; node = node->next;
    }
    cout << endl;
}

int main()
{
    ListNode* head = NULL;
    Solution solution;
    readInput({}, &head);
    head = solution.deleteSecondNode(head);
    printList(head);
    return 0;
}
